export const grActivities: Activity[] = [
  {"id":"gr-over-under-ball-relay","title":"Over-Under Ball Brigade","altNames":["Over and Under Pass","Tunnel and Arch Relay","Up-Down Ball Pass"],"type":"Game","place":"Both","ageMin":7,"ageMax":14,"durationMin":30,"groupMin":8,"groupMax":30,"energy":2,"prep":"Low","blurb":"Teams stand in a line and rocket a ball backward over a head, then under the legs, then over again until it reaches the end and races to the front.","materials":["Playground balls, one per team","Cones to mark the finish line, 2-4"],"materialTags":["Playground balls","Cones"],"steps":["Split the group into even lines of 6-10, everyone facing the same direction with arm's length between players.","The front player passes the ball over their head to the person behind, who passes it under their legs to the next, alternating over-under all the way down.","When the last player gets the ball, they run to the front of their line and start a new over-under pass.","Continue until the team's original front player returns to the front, or until the line crosses a finish line by leapfrogging forward.","First team to fully cycle through (or reach the cone line) wins the round.","Reset and run a best-of-three."],"notes":"Keep lines short for younger kids so the ball doesn't travel too far; if a line keeps fumbling, have them spread their feet wider for the under-pass.","safety":"Remind players to bend their knees and look down on the under-pass so no one bumps heads with the person behind them.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Over Under Relay demo","url":"https://www.youtube.com/watch?v=WeCELuNRZGU"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/relay-race-ideas/"}],"variations":["Use two balls per line started at opposite ends so they cross in the middle.","Switch to all-under or all-over for an easier version with the youngest groups."],"subsets":[["Even teams matter more than big teams; cap lines at 10."],["Demonstrate the alternating rhythm once slowly before starting."],[],[],[],[]]},
  {"id":"gr-beanbag-balance-relay","title":"Head-Balance Beanbag Dash","altNames":["Balance Carry Race","Beanbag on the Head Relay","Steady Head Relay"],"type":"Game","place":"Both","ageMin":6,"ageMax":13,"durationMin":30,"groupMin":6,"groupMax":24,"energy":2,"prep":"Low","blurb":"Racers walk a course balancing a beanbag on their head, and if it drops they must freeze, replace it, and carry on.","materials":["Beanbags, one per team","Cones to mark turnaround points, 2-6"],"materialTags":["Beanbag","Cones"],"steps":["Set a turnaround cone about 10-15 paces out for each team and line teams up behind a start line.","On 'go,' the first racer balances a beanbag on their head and walks to the cone and back without using hands.","If the beanbag falls, the racer must stop, place it back on their head, and continue from that spot.","Back at the line, they hand the beanbag to the next teammate.","The first team to get everyone through wins.","Run a second round walking heel-to-toe for an added balance challenge."],"notes":"Tell kids slow-and-steady beats fast-and-fumbling; this naturally calms a rowdy group. Place the beanbag flat for the best grip.","safety":"Players must keep their eyes up and walk, never run, so they don't trip while looking forward instead of down.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Bean Bag Balance walk","url":"https://www.youtube.com/watch?v=qwATvUj30eA"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/team-building-games-and-activities/"}],"variations":["Balance the beanbag on the back of one hand instead of the head for older kids.","Add a single hula hoop to step through partway as an extra obstacle."],"subsets":[["Space teams far apart so racers don't collide at the turnaround."],[],["No hands rule is the heart of the game; enforce gently."],[],[],[]]},
  {"id":"gr-dry-sponge-fill-relay","title":"Dry Cup Stack Relay","altNames":["Cup Transport Race","Stack-and-Run Relay","Build the Tower Relay"],"type":"Game","place":"Both","ageMin":6,"ageMax":14,"durationMin":30,"groupMin":6,"groupMax":24,"energy":2,"prep":"Low","blurb":"Runners ferry one paper cup at a time across the field to build the tallest, sturdiest stack before time runs out.","materials":["Paper cups, 20-30 per team","Cones to mark the building zone, 2-4"],"materialTags":["Paper cups","Cones"],"steps":["Place a pile of paper cups at the start line and mark a building zone for each team about 12 paces away.","On 'go,' the first runner grabs exactly one cup, runs it to the building zone, and adds it to a stack or pyramid.","They run back and tag the next teammate, who carries the next cup.","Teams keep cycling, building the tallest stable tower or pyramid they can.","After three minutes, call freeze; the tallest standing structure wins, but a collapsed tower scores zero.","Reset and play again, letting teams plan their structure first."],"notes":"The strategy of pyramid-versus-tower makes this great for older kids; younger groups do better just stacking rims-up. One cup per trip keeps everyone moving.","safety":"Keep the running lane clear of the building zone so a runner returning at speed doesn't crash into kids placing cups.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Cup Stacking Relay Race","url":"https://www.youtube.com/watch?v=qoDewxSR8dw"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/"}],"variations":["Require alternating cup orientation (up, down, up) to force a sturdier wall.","Let two builders work the structure while the rest run, for a teamwork twist."],"subsets":[["Pre-count cups so each team starts with the same number."],[],[],["Encourage a team huddle to assign a 'stacker' role."],[],[]]},
  {"id":"gr-three-legged-shuttle","title":"Three-Legged Shuttle Sprint","altNames":["Tied-Leg Race","Partner Leg Relay","Buddy Bind Race"],"type":"Game","place":"Outside","ageMin":8,"ageMax":15,"durationMin":30,"groupMin":8,"groupMax":24,"energy":3,"prep":"Low","blurb":"Pairs bound down the course with their inside legs tied together, then untie and hand the band to the next duo.","materials":["Soft fabric strips or wide rubber bands, one per pair","Cones to mark the turnaround, 2-4"],"materialTags":["Rubber bands","Cones"],"steps":["Pair players by similar height and have each pair stand side by side.","Tie the inside ankles together loosely with a fabric strip so the pair shares a 'third leg.'","On 'go,' the bound pair calls 'in-out' to sync steps and travels to the turnaround cone and back.","They untie and hand the strip to the next waiting pair, who tie up and go.","First team to send all pairs through wins.","Swap partners and run a rematch the other direction."],"notes":"Coach the 'inside-leg-together' chant; pairs who talk it out are far faster. Group by height so steps match. This one tends to dissolve into laughter.","safety":"Tie the ankles, never above the knee, and keep the binding loose enough that a stumbling pair can break free quickly to avoid a hard fall.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Run a Three-Legged Race","url":"https://www.youtube.com/watch?v=VtScuwFwRRs"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/relay-race-ideas/"}],"variations":["Walk instead of run for younger or unsteady groups.","Make it a foursome four-legged race for a tougher coordination test."],"subsets":[["Match heights to keep stride lengths similar."],["Demonstrate a safe loose knot at the ankle."],["The 'in-out' verbal cue is the trick to staying upright."],[],[],[]]},
  {"id":"gr-wheelbarrow-relay","title":"Wheelbarrow Walk Relay","altNames":["Hands-and-Feet Race","Partner Push Relay","Wheelbarrow Race"],"type":"Game","place":"Outside","ageMin":8,"ageMax":15,"durationMin":30,"groupMin":8,"groupMax":24,"energy":3,"prep":"Low","blurb":"One partner walks on their hands while the other holds their ankles like a wheelbarrow, racing to a cone and swapping roles.","materials":["Cones to mark the turnaround, 2-4","Open grassy space"],"materialTags":["Cones"],"steps":["Pair players and have one get into a plank with hands on the ground; the partner gently lifts their ankles.","On 'go,' the 'wheelbarrow' walks forward on their hands while the partner steps behind holding the legs.","At the turnaround cone, partners switch roles and return to the start.","Tag the next pair, who repeat the hands-and-feet trip.","First team with all pairs finished wins.","Run again so everyone gets both roles."],"notes":"Best on soft grass and short distances; arms tire fast. Pair kids of similar strength. Skip this if a child has a wrist injury.","safety":"The holder must lift the ankles, not the knees, and walk slowly so the wheelbarrow's hands never get yanked out from under them.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Wheelbarrow races","url":"https://www.youtube.com/watch?v=d1w2fC-eW6U"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/team-building-games-and-activities/"}],"variations":["Shorten the course to half-distance for younger campers.","Let the wheelbarrow choose a crawl instead, for any pair that prefers it."],"subsets":[["Pair by similar height and strength."],["Keep the hold low at the ankles for control."],[],[],[],[]]},
  {"id":"gr-hula-hoop-pass-circle","title":"Hula Hoop Pass-Through","altNames":["Hoop Around the Circle","Pass the Hoop Race","Hoop Relay Loop"],"type":"Game","place":"Both","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":8,"groupMax":24,"energy":2,"prep":"Low","blurb":"Teams hold hands in a line and shimmy a hula hoop from one end to the other without ever letting go.","materials":["Hula hoops, one per team","Open space or gym"],"materialTags":["Hula hoops"],"steps":["Have each team stand in a line holding hands, and hang a hula hoop over the joined hands at one end.","On 'go,' the first player steps and ducks through the hoop, passing it along the line without releasing hands.","Each player wriggles through in turn, working the hoop down the chain.","If hands separate, the hoop goes back to that pair and they redo the pass.","The first team to move the hoop all the way to the far end wins.","For a finale, form one big circle and race the hoop all the way around."],"notes":"Two hoops sent in opposite directions doubles the chaos for experienced groups. Coach taller kids to crouch so smaller ones can reach.","safety":"Players should step through the hoop one foot at a time rather than jumping, so a tangled hoop doesn't trip the whole linked line.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Hula Hoop Pass team activity","url":"https://www.youtube.com/watch?v=11LNy8IOg8Y"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/"}],"variations":["Send two hoops from opposite ends so they must pass each other mid-line.","Time a single big circle and challenge the group to beat their own record."],"subsets":[["A line works for racing; a full circle works for a cooperative timed challenge."],[],[],["The no-letting-go rule is what makes it a team challenge."],[],[]]},
  {"id":"gr-blindfold-guide-course","title":"Trust Voice Maze","altNames":["Blindfold Navigation","Guide My Steps","Voice-Led Obstacle Walk"],"type":"Game","place":"Both","ageMin":9,"ageMax":16,"durationMin":30,"groupMin":6,"groupMax":20,"energy":2,"prep":"Medium","blurb":"A blindfolded walker crosses a field of soft obstacles steered only by a partner's calm voice from the sideline.","materials":["Blindfolds or bandanas, one per pair","Soft obstacles: cones, beanbags, pool noodles","Cones to outline the course"],"materialTags":["Cones","Beanbag"],"steps":["Scatter soft obstacles across a marked rectangle to form a gentle maze.","One partner is blindfolded at the start; the other stands at the far end and may only use words, never touch.","On 'go,' the guide calls clear directions to steer their walker through without bumping an obstacle.","Touching an obstacle adds a five-second penalty; reaching the far end stops the clock.","Partners swap roles and run it again.","Lowest combined time across both partners wins."],"notes":"Reset obstacles between runs so no one memorizes the path. Coach guides to give short, specific cues like 'two small steps left.' Great for building listening.","safety":"All obstacles must be soft, and have a counselor shadow each blindfolded walker to catch any wandering toward the field edge.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Blindfold obstacle challenge","url":"https://www.youtube.com/watch?v=n-xV_ngi9zY"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/relay-race-ideas/"}],"variations":["Run several walkers at once so guides must shout over each other.","Add a midpoint where the walker collects a beanbag before finishing."],"subsets":[["Use only soft items so a bump never hurts."],["Stress that guides may not run onto the course."],[],[],[],[]]},
  {"id":"gr-tarp-flip-challenge","title":"The Magic Tarp Flip","altNames":["Flip the Blanket","Tarp Turnover","Group Flip Challenge"],"type":"Game","place":"Both","ageMin":9,"ageMax":16,"durationMin":30,"groupMin":6,"groupMax":16,"energy":2,"prep":"Low","blurb":"A whole team crowds onto a tarp and must flip it completely over without anyone stepping off the fabric.","materials":["A tarp or bedsheet, one per team","Open space"],"materialTags":["Tarp or bedsheet"],"steps":["Spread a tarp on the ground and have the whole team stand on one half of it.","Explain the goal: flip the tarp entirely over so they end up standing on what was the underside, with no one touching the ground.","Anyone who steps off the tarp sends the whole team back to the start.","The team must talk, plan, and shuffle together, slowly folding and walking the tarp over.","The round ends when the tarp is fully flipped and everyone is on it.","Make it harder by starting with a larger tarp and folding it smaller each round."],"notes":"Start the team on a tarp sized so it's a bit crowded; too roomy is too easy. The trick is shifting weight to a corner. Let them strategize before starting.","safety":"Remind the team to move slowly and avoid piling onto one spot so no one gets squeezed or knocked over during the flip.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Flip the Tarp team exercise","url":"https://www.youtube.com/watch?v=d5V1a2Ya30M"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/team-building-games-and-activities/"}],"variations":["Use a smaller tarp or fold it in half to ramp up difficulty.","Forbid talking partway through so they must coordinate with gestures."],"subsets":[[],["The no-touching-ground rule is the whole puzzle."],[],["Encourage a planning huddle before the first move."],[],[]]},
  {"id":"gr-pass-the-knot-tag","title":"Knot Pass Sprint Relay","altNames":["Untangle and Run","Rope Knot Relay","Tie-and-Pass Race"],"type":"Game","place":"Both","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":8,"groupMax":24,"energy":2,"prep":"Low","blurb":"Each runner sprints to a station, ties one simple knot in a rope, then races back so the next teammate can add theirs.","materials":["Soft ropes or yarn lengths, one per team","Cones to mark the knot station, 2-4"],"materialTags":["Yarn","Cones"],"steps":["Lay a length of soft rope at a station cone about 12 paces from each team's line.","Demonstrate one simple overhand knot everyone will tie.","On 'go,' the first runner sprints to the rope, ties one neat overhand knot, and races back to tag the next teammate.","Each runner adds exactly one knot until the whole team has gone.","First team to finish with all knots correctly tied wins; a counselor checks the knots.","For round two, runners must untie one knot each instead of tying."],"notes":"Teach the knot to the whole group first so the race isn't a tying lesson. Untie-mode is a nice cooldown round. Use thick rope for easy gripping.","safety":"Keep ropes short and untied between rounds so a loose loop on the ground doesn't become a trip hazard in the running lane.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Knot Tying Rescue Relay","url":"https://www.youtube.com/watch?v=2tZazYXr8rI"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/"}],"variations":["Use a figure-eight knot for older, knot-savvy groups.","Make the final runner tie all the knots into a single long chain."],"subsets":[[],["Practice the overhand knot together before the clock starts."],[],[],["Have a counselor verify knots so speed-without-quality doesn't win."],[]]},
  {"id":"gr-caterpillar-shuffle","title":"Caterpillar Crawl Relay","altNames":["Conga Shuffle Race","Linked Line Relay","Inchworm Team Race"],"type":"Game","place":"Both","ageMin":7,"ageMax":14,"durationMin":30,"groupMin":8,"groupMax":24,"energy":2,"prep":"Low","blurb":"Teams link up nose-to-tail and shuffle as one wobbly caterpillar to the turnaround and back without breaking apart.","materials":["Cones to mark the turnaround, 2-4","Open space"],"materialTags":["Cones"],"steps":["Form each team into a line, each player placing both hands on the shoulders of the person ahead.","On 'go,' the whole connected 'caterpillar' shuffles together toward the turnaround cone.","If the chain breaks, the team must stop, reconnect at that spot, and continue.","Once the front player rounds the cone, the caterpillar returns to the start line.","The whole caterpillar must cross the finish still connected to win.","Run again with the line facing the other way so a new player leads."],"notes":"Coach the front player to take small steps so the tail can keep up. Add a fun rule that the caterpillar must sync a left-right step chant. Great icebreaker.","safety":"Players must walk or shuffle, never run, while connected, since a sudden sprint up front can yank the line and topple kids at the back.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Caterpillar Race for kids","url":"https://www.youtube.com/watch?v=IEmoCNyqkLI"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/relay-race-ideas/"}],"variations":["Have the whole caterpillar duck under a held hula hoop midway.","Add a beanbag passed hand-over-shoulder up the line while moving."],"subsets":[[],["The connected-line rule is essential; reconnect if it breaks."],[],[],[],[]]},
  {"id":"gr-cup-water-free-spoon-relay","title":"Spoon Ball Carry Relay","altNames":["Egg-and-Spoon Race","Balance Spoon Relay","Ball-on-Spoon Dash"],"type":"Game","place":"Both","ageMin":6,"ageMax":13,"durationMin":30,"groupMin":6,"groupMax":24,"energy":2,"prep":"Low","blurb":"Racers balance a small ball on a spoon held at arm's length, walking the course and starting over if it rolls off.","materials":["Plastic spoons, one per team","Small lightweight balls (such as ping-pong or foam), one per team","Cones to mark the turnaround, 2-4"],"materialTags":["Cones","Playground balls"],"steps":["Give the first racer on each team a spoon with a small ball resting in the bowl.","On 'go,' they walk to the turnaround cone and back holding the spoon out front, no other hand on the ball.","If the ball drops, the racer stops, retrieves it, replaces it, and continues from that spot.","Back at the line, they hand the spoon and ball to the next teammate.","First team to get everyone through wins.","Play a calmer round where a dropped ball sends the racer back to the start line."],"notes":"Lightweight foam balls roll less than ping-pong balls for younger kids. The drop-and-restart rule rewards control over speed and settles wound-up groups.","safety":"Racers should keep their eyes on the path ahead, not glued to the spoon, so they don't walk into a teammate or the turnaround cone.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Play Egg and Spoon Race","url":"https://www.youtube.com/watch?v=A46fcdc-qcU"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/team-building-games-and-activities/"}],"variations":["Hold the spoon handle in the mouth for an older-camper challenge.","Use a slightly larger ball and a bigger serving spoon for the youngest group."],"subsets":[["Foam balls are far more forgiving than ping-pong balls."],[],[],[],[],[]]},
  {"id":"gr-stepping-stone-crossing","title":"Stepping-Stone River Crossing","altNames":["Carpet Square Crossing","Island Hop Challenge","Lava River Tiles"],"type":"Game","place":"Both","ageMin":8,"ageMax":15,"durationMin":30,"groupMin":6,"groupMax":18,"energy":2,"prep":"Medium","blurb":"A team must ferry everyone across an imaginary river using only a few movable 'stepping stones' that vanish the moment no one is touching them.","materials":["Carpet squares, foam tiles, or paper plates as stones (one fewer than the team size)","Cones to mark the river banks, 2-4"],"materialTags":["Paper plates","Cones"],"steps":["Mark two river banks a fixed distance apart and give the team a few 'stepping stones,' always one fewer than the number of players.","Explain that feet may only touch stones, never the 'river' ground between the banks.","A stone left untouched by any hand or foot is whisked away by a counselor, so someone must always keep a hand on each stone.","The team works together to pass stones forward and shuffle everyone across.","If anyone touches the river or loses a stone, the whole team restarts from the first bank.","The challenge ends when the entire team stands safely on the far bank."],"notes":"Sizing the gap so it takes real teamwork is the key; start narrow and widen it each success. Let the team plan first. This builds great problem-solving talk.","safety":"Use non-slip stones and keep the crossing on a flat, dry surface so a player balancing on a tile doesn't slip when shifting weight.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Stepping Stones River Crossing","url":"https://www.youtube.com/watch?v=rz-eea5Yv2M"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/"}],"variations":["Remove one more stone to crank up the difficulty for older groups.","Add a 'carry the bucket' twist where one harmless object must also cross."],"subsets":[["Give the team one fewer stone than players so passing is forced."],[],["A counselor enforcing the 'untouched stone disappears' rule keeps it honest."],[],[],[]]},
  {"id":"gr-human-chain-object-pass","title":"Bucket Brigade Object Pass","altNames":["Fire Line Relay","Hand-Off Chain","Pass-It-Down Line"],"type":"Game","place":"Both","ageMin":6,"ageMax":14,"durationMin":30,"groupMin":8,"groupMax":30,"energy":2,"prep":"Low","blurb":"Teams form a line and speed-pass a stack of soft objects hand to hand from one end to a collection bin at the other.","materials":["Soft objects to pass: beanbags, foam balls, rolled socks (10-15 per team)","A bin, box, or hula hoop as the collection spot per team"],"materialTags":["Beanbag","Hula hoops"],"steps":["Stand each team in a line with a pile of soft objects at one end and an empty bin or hoop at the other.","On 'go,' the first player picks up one object and passes it down the line hand to hand.","The last player drops each object into the bin; no throwing and no skipping people allowed.","Players keep the items flowing as fast as they can without dropping them.","First team to move every object into the bin wins; a dropped item must be passed back up to its drop point.","Reset and try a 'reverse the line' round, passing items back to the start."],"notes":"Encourage a steady rhythm over frantic grabbing; teams that overlap hands smoothly win. Spread players a full arm's length apart so passing requires real reach.","safety":"Pass only soft items hand-to-hand and ban throwing, so no one gets hit by a tossed object when the line speeds up.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"PE Games: Bucket Brigade","url":"https://www.youtube.com/watch?v=ghx3Fy-quPw"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/relay-race-ideas/"}],"variations":["Have two lines race head-to-head with identical object piles.","Mix in one 'fragile' item (a stacked cup tower) that must arrive intact."],"subsets":[[],[],["The no-throwing rule keeps it safe and fair."],[],[],[]]},
  {"id":"gr-build-the-shape-relay","title":"Build-the-Shape Card Relay","altNames":["Picture Puzzle Relay","Pattern Build Race","Reconstruct the Design"],"type":"Game","place":"Both","ageMin":8,"ageMax":15,"durationMin":30,"groupMin":6,"groupMax":24,"energy":2,"prep":"Medium","blurb":"Runners sprint one at a time to glimpse a hidden picture, dash back, and place a single craft stick to rebuild the design from memory.","materials":["A hidden reference picture per team (a simple shape drawn on paper)","Craft sticks, 15-20 per team","A flat building area and a screen or folder to hide the reference"],"materialTags":["Paper","Craft sticks"],"steps":["Draw a simple shape made of straight lines (like a house or star) and hide a copy near each team's far cone.","On 'go,' the first runner sprints to peek at the hidden picture for a few seconds, then races back.","Back at the team's building area, the team places exactly one craft stick to match what the runner saw.","The next runner goes, peeks, returns, and the team adds another stick.","Teams continue until their craft-stick build matches the hidden reference.","First team to correctly recreate the full shape wins; closest match wins if time runs out."],"notes":"This blends memory, communication, and running, so it suits older campers. Keep designs simple (6-10 lines). Let the runner describe out loud while the team builds.","safety":"Set the peek station and the building area apart so returning runners at a sprint don't collide with teammates kneeling to place sticks.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Memory Relay Challenge","url":"https://www.youtube.com/watch?v=CQn-XfK-8-s"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/team-building-games-and-activities/"}],"variations":["Forbid talking so the runner must point and gesture only.","Use a more complex multi-shape design for a longer, harder round."],"subsets":[["Keep the reference shape to straight lines so craft sticks can match it."],[],["One stick per runner forces real teamwork and memory."],[],[],[]]},
];
